select ndgssr.nx_distributer_goods_shelf_stock_reduce_id, ndgssr.nx_dgssr_nx_distributer_id, ndgssr.nx_dgssr_nx_dis_goods_id, ndgssr.nx_dgssr_nx_dis_goods_father_id, ndgssr.nx_dgssr_nx_stock_id, ndgssr.nx_dgssr_date, ndgssr.nx_dgssr_week, ndgssr.nx_dgssr_month, ndgssr.nx_dgssr_full_time, ndgssr.nx_dgssr_type, ndgssr.nx_dgssr_do_user_id, ndgssr.nx_dgssr_cost_weight, ndgssr.nx_dgssr_cost_subtotal, ndgssr.nx_dgssr_waste_weight, ndgssr.nx_dgssr_waste_subtotal, ndgssr.nx_dgssr_loss_weight, ndgssr.nx_dgssr_loss_subtotal, ndgssr.nx_dgssr_produce_weight, ndgssr.nx_dgssr_produce_subtotal, ndgssr.nx_dgssr_return_weight, ndgssr.nx_dgssr_return_subtotal, ndgssr.nx_dgssr_nx_pur_goods_id, ndgssr.nx_dgssr_nx_dep_order_id, ndgssr.nx_dgssr_status, nd.nx_department_name as departmentName, ndo.nx_DO_quantity as orderQuantity, ndo.nx_DO_standard as orderStandard, du.nx_DIU_wx_nick_name as doUserName from nx_distributer_goods_shelf_stock_reduce as ndgssr left join nx_department_orders as ndo on ndo.nx_department_orders_id = ndgssr.nx_dgssr_nx_dep_order_id left join nx_department as nd on nd.nx_department_id = ndo.nx_DO_department_id left join nx_distributer_user as du on du.nx_distributer_user_id = ndgssr.nx_dgssr_do_user_id
and ndgssr.nx_dgssr_nx_dis_goods_id = #{disGoodsId}
and ndgssr.nx_dgssr_nx_distributer_id = #{disId}
and ndgssr.nx_dgssr_date >= #{startDate}
and ndgssr.nx_dgssr_date <= #{stopDate}
and ndgssr.nx_dgssr_type = #{equalType}
and ndgssr.nx_dgssr_type in
#{typeItem}
and FIND_IN_SET(ndgssr.nx_dgssr_type, #{typesStr})
order by ndgssr.nx_dgssr_date DESC, ndgssr.nx_dgssr_full_time DESC

select dg.nx_distributer_goods_id, dg.nx_dg_goods_name, dg.nx_dg_goods_standardname, dg.nx_dg_goods_standard_weight, dg.nx_dg_goods_detail, dg.nx_dg_goods_brand, dg.nx_dg_goods_place, dg.nx_dg_goods_file, dg.nx_dg_goods_file_large, dg.nx_dg_carton_unit, dg.nx_dg_items_per_carton,
#{disId} AS disId, #{startDate} AS startDate, #{stopDate} AS stopDate,
#{equalType} AS equalType,
NULL AS equalType,
#{typesStr} AS typesStr,
NULL AS typesStr,
IFNULL(sum(CASE WHEN ndgssr.nx_dgssr_type IN (0, 1) THEN ndgssr.nx_dgssr_cost_subtotal ELSE 0 END), 0) as goodsSalesTotal, IFNULL(sum(CASE WHEN ndgssr.nx_dgssr_type IN (2, 3) THEN (COALESCE(ndgssr.nx_dgssr_waste_subtotal, 0) + COALESCE(ndgssr.nx_dgssr_loss_subtotal, 0)) ELSE 0 END), 0) as goodsLossTotal, IFNULL(sum(CASE WHEN ndgssr.nx_dgssr_type = 4 THEN ndgssr.nx_dgssr_cost_subtotal ELSE 0 END), 0) as goodsReturnTotal from nx_distributer_goods_shelf_stock_reduce as ndgssr left join nx_distributer_goods as dg on dg.nx_distributer_goods_id = ndgssr.nx_dgssr_nx_dis_goods_id
left join nx_distributer_father_goods as ndfg on ndfg.nx_distributer_father_goods_id = dg.nx_dg_dfg_goods_grand_id
and ndgssr.nx_dgssr_nx_distributer_id = #{disId}
and ndgssr.nx_dgssr_date >= #{startDate}
and ndgssr.nx_dgssr_date <= #{stopDate}
and ndgssr.nx_dgssr_type = #{equalType}
and ndgssr.nx_dgssr_type in
#{typeItem}
and ndfg.nx_dfg_fathers_father_id = #{disGoodsGreatId}
group by dg.nx_distributer_goods_id
order by goodsSalesTotal DESC
order by goodsLossTotal DESC
order by goodsReturnTotal DESC
order by dg.nx_dg_goods_name
limit #{offset}, #{limit}

select * from nx_distributer_goods_shelf_stock_reduce

	nx_dgssr_nx_stock_id = #{stockId}
	and nx_dgssr_type = 2

		and nx_dgssr_date = #{inventoryDate}


		and nx_dgssr_week = #{inventoryWeek}


		and nx_dgssr_month = #{inventoryMonth}


limit 1

SELECT dg.nx_distributer_goods_id, dg.nx_dg_goods_name, dg.nx_dg_goods_standardname, dg.nx_dg_goods_standard_weight, dg.nx_dg_goods_detail, dg.nx_dg_goods_brand, dg.nx_dg_goods_place, dg.nx_dg_goods_file, dg.nx_dg_goods_file_large, dg.nx_dg_carton_unit, dg.nx_dg_items_per_carton, ROUND(SUM(ndgssr.nx_dgssr_cost_subtotal), 1) AS goodsSalesTotal FROM nx_distributer_goods_shelf_stock_reduce ndgssr LEFT JOIN nx_distributer_goods dg ON dg.nx_distributer_goods_id = ndgssr.nx_dgssr_nx_dis_goods_id WHERE 1=1
AND ndgssr.nx_dgssr_nx_distributer_id = #{disId}
AND ndgssr.nx_dgssr_date >= #{startDate}
AND ndgssr.nx_dgssr_date <= #{stopDate}
AND ndgssr.nx_dgssr_do_user_id IN
#{userId}
AND ndgssr.nx_dgssr_type IN (0, 1) GROUP BY ndgssr.nx_dgssr_nx_dis_goods_id, dg.nx_dg_goods_name ORDER BY goodsSalesTotal DESC LIMIT 10

SELECT dg.nx_distributer_goods_id, dg.nx_dg_goods_name, dg.nx_dg_goods_standardname, dg.nx_dg_goods_standard_weight, dg.nx_dg_goods_detail, dg.nx_dg_goods_brand, dg.nx_dg_goods_place, dg.nx_dg_goods_file, dg.nx_dg_goods_file_large, dg.nx_dg_carton_unit, dg.nx_dg_items_per_carton, ROUND(SUM(COALESCE(ndgssr.nx_dgssr_waste_subtotal, 0) + COALESCE(ndgssr.nx_dgssr_loss_subtotal, 0)), 1) AS goodsLossTotal FROM nx_distributer_goods_shelf_stock_reduce ndgssr LEFT JOIN nx_distributer_goods dg ON dg.nx_distributer_goods_id = ndgssr.nx_dgssr_nx_dis_goods_id WHERE 1=1
AND ndgssr.nx_dgssr_nx_distributer_id = #{disId}
AND ndgssr.nx_dgssr_date >= #{startDate}
AND ndgssr.nx_dgssr_date <= #{stopDate}
AND ndgssr.nx_dgssr_do_user_id IN
#{userId}
AND ndgssr.nx_dgssr_type IN (2, 3) GROUP BY ndgssr.nx_dgssr_nx_dis_goods_id ORDER BY goodsLossTotal DESC LIMIT 10

SELECT dg.nx_distributer_goods_id, dg.nx_dg_goods_name, dg.nx_dg_goods_standardname, dg.nx_dg_goods_standard_weight, dg.nx_dg_goods_detail, dg.nx_dg_goods_brand, dg.nx_dg_goods_place, dg.nx_dg_goods_file, dg.nx_dg_goods_file_large, dg.nx_dg_carton_unit, dg.nx_dg_items_per_carton, ROUND(SUM(ndgssr.nx_dgssr_waste_subtotal), 1) AS goodsWasteTotal FROM nx_distributer_goods_shelf_stock_reduce ndgssr LEFT JOIN nx_distributer_goods dg ON dg.nx_distributer_goods_id = ndgssr.nx_dgssr_nx_dis_goods_id WHERE 1=1
