AND ndgssr.nx_dgssr_date <= #{stopDate}
AND ndgssr.nx_dgssr_do_user_id IN
#{userId}
AND ndgssr.nx_dgssr_type = 2 GROUP BY ndgssr.nx_dgssr_nx_dis_goods_id ORDER BY goodsWasteTotal DESC LIMIT 10

SELECT ndgssr.nx_dgssr_date AS date, ROUND(SUM(COALESCE(ndgssr.nx_dgssr_cost_subtotal, 0)), 1) AS goodsProduceTotal FROM nx_distributer_goods_shelf_stock_reduce ndgssr WHERE 1=1
